"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([["9546"],{11(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","href":"/Sarke2.0/docs/","label":"Sarke 2.0","docId":"intro","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/architecture","label":"Architecture","docId":"architecture","unlisted":false},{"type":"category","label":"Routes","collapsed":false,"items":[{"type":"link","href":"/Sarke2.0/docs/routes/auth","label":"Auth Routes","docId":"routes/auth","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/routes/tabs","label":"Tab Routes","docId":"routes/tabs","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/routes/inspections","label":"Inspection Routes","docId":"routes/inspections","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/routes/projects","label":"Project Routes","docId":"routes/projects","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/routes/certificates","label":"Certificate Routes","docId":"routes/certificates","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/routes/qualifications","label":"Qualification Routes","docId":"routes/qualifications","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/routes/misc","label":"Misc Routes","docId":"routes/misc","unlisted":false}],"collapsible":true},{"type":"link","href":"/Sarke2.0/docs/components","label":"Components","docId":"components","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/lib","label":"Lib Reference","docId":"lib","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/data-model","label":"Data Model","docId":"data-model","unlisted":false},{"type":"category","label":"Database","collapsed":false,"items":[{"type":"link","href":"/Sarke2.0/docs/database/schema","label":"Database Schema","docId":"database/schema","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/database/migrations","label":"Migrations","docId":"database/migrations","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/database/api","label":"REST API (Swagger)","docId":"database/api","unlisted":false}],"collapsible":true},{"type":"link","href":"/Sarke2.0/docs/pdf-generation","label":"PDF Generation","docId":"pdf-generation","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/offline-sync","label":"Offline & Sync","docId":"offline-sync","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/signing-flow","label":"Signing Flow","docId":"signing-flow","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/deployment","label":"Deployment","docId":"deployment","unlisted":false},{"type":"link","href":"/Sarke2.0/docs/contributing","label":"Contributing","docId":"contributing","unlisted":false}]},"docs":{"architecture":{"id":"architecture","title":"Architecture","description":"Sarke 2.0 is a client-only mobile app talking directly to Supabase \u2014 there is no custom HTTP backend. All reads and writes go through the Supabase JS SDK; PostgREST + RLS is the API.","sidebar":"docsSidebar"},"components":{"id":"components","title":"Components","description":"Reusable UI under components/. None of them call Supabase directly \u2014 they take props (data + callbacks) and render. Data fetching belongs in route screens or services.","sidebar":"docsSidebar"},"contributing":{"id":"contributing","title":"Contributing","description":"Editing these docs","sidebar":"docsSidebar"},"data-model":{"id":"data-model","title":"Data Model","description":"TypeScript mirror lives in types/models.ts; SQL source of truth is supabase/migrations/0001_init.sql plus follow-up migrations.","sidebar":"docsSidebar"},"database/api":{"id":"database/api","title":"REST API (Swagger)","description":"Supabase auto-generates a PostgREST API for every table, with row-level-security applied at the database. The schema below is fetched live from https://seskuthiopywrgntsgfw.supabase.co/rest/v1/?apikey= and saved to /openapi.json.","sidebar":"docsSidebar"},"database/migrations":{"id":"database/migrations","title":"Migrations","description":"supabase/migrations/00*.sql \u2014 applied in order against the hosted Supabase project. Each migration is intentionally small and self-contained.","sidebar":"docsSidebar"},"database/schema":{"id":"database/schema","title":"Database Schema","description":"Postgres 15+ on Supabase. All user-scoped tables have Row-Level Security turned on, scoping reads and writes to auth.uid().","sidebar":"docsSidebar"},"deployment":{"id":"deployment","title":"Deployment","description":"App (EAS Build)","sidebar":"docsSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"Prerequisites","sidebar":"docsSidebar"},"intro":{"id":"intro","title":"Sarke 2.0","description":"Sarke 2.0 is an Expo / React Native mobile app for Georgian scaffolding (\u10EE\u10D0\u10E0\u10D0\u10E9\u10DD) safety inspections. An expert opens the app, picks a project, walks through a templated checklist on site, attaches photos, collects signatures from the crew, and generates a PDF certificate.","sidebar":"docsSidebar"},"lib":{"id":"lib","title":"Lib Reference","description":"Everything under lib/. The lib layer owns Supabase calls, cross-cutting concerns, and any logic that isn\'t a screen.","sidebar":"docsSidebar"},"offline-sync":{"id":"offline-sync","title":"Offline & Sync","description":"Inspections are filled in on remote sites where connectivity is patchy. The app aims to \\"keep working\\" offline and reconcile when the network returns.","sidebar":"docsSidebar"},"pdf-generation":{"id":"pdf-generation","title":"PDF Generation","description":"Inspection certificates are rendered locally on the device \u2014 there is no server-side PDF service.","sidebar":"docsSidebar"},"routes/auth":{"id":"routes/auth","title":"Auth Routes","description":"app/(auth)/* \u2014 screens shown to unauthenticated users (and a couple of recovery flows for authed users). The (auth) group\'s layout (app/(auth)/_layout.tsx) renders without the bottom tab bar.","sidebar":"docsSidebar"},"routes/certificates":{"id":"routes/certificates","title":"Certificate Routes","description":"A certificate is the PDF artifact generated from a completed inspection. The same inspection can have many certificates over time (re-generated on demand).","sidebar":"docsSidebar"},"routes/inspections":{"id":"routes/inspections","title":"Inspection Routes","description":"The inspection flow is the core of the app: pick a template, walk through the questions, sign, generate a certificate.","sidebar":"docsSidebar"},"routes/misc":{"id":"routes/misc","title":"Misc Routes","description":"| Path | File | Purpose |","sidebar":"docsSidebar"},"routes/projects":{"id":"routes/projects","title":"Project Routes","description":"| Path | File | Purpose |","sidebar":"docsSidebar"},"routes/qualifications":{"id":"routes/qualifications","title":"Qualification Routes","description":"A qualification is the expert\'s professional credential (e.g. xarachoinspector certificate with number, issue + expiry dates, scanned PDF). Templates can require specific qualification types via templates.requiredqualifications; missing quals block inspection start.","sidebar":"docsSidebar"},"routes/tabs":{"id":"routes/tabs","title":"Tab Routes","description":"app/(tabs)/* \u2014 the main bottom-tab navigation for an authenticated user.","sidebar":"docsSidebar"},"signing-flow":{"id":"signing-flow","title":"Signing Flow","description":"The end of an inspection collects signatures from a set of roles defined on the template (requiredsignerroles). There are two delivery modes: on-site and remote.","sidebar":"docsSidebar"}}}}')}}]);